32: // non-const so modifiable by tests
33: var (
34: 	// chanBufLen is the length of the buffered chan
35: 	// for sending out watched events.
36: 	// See https://github.com/etcd-io/etcd/issues/11906 for more detail.
37: 	chanBufLen = 128
38: 
39: 	// maxWatchersPerSync is the number of watchers to sync in a single batch
40: 	maxWatchersPerSync = 512
