46: func ChanBufLen() int { return chanBufLen }
47: 
48: type watchable interface {
49: 	watch(key, end []byte, startRev int64, id WatchID, ch chan<- WatchResponse, fcs ...FilterFunc) (*watcher, cancelFunc)
50: 	progress(w *watcher)
51: 	progressAll(watchers map[WatchID]*watcher) bool
52: 	rev() int64
53: }
54: 
55: type watchableStore struct {
56: 	*store
57: 
58: 	// mu protects watcher groups and batches. It should never be locked
59: 	// before locking store.mu to avoid deadlock.
60: 	mu sync.RWMutex
61: 
62: 	// victims are watcher batches that were blocked on the watch channel
63: 	victims []watcherBatch
64: 	victimc chan struct{}
65: 
66: 	// contains all unsynced watchers that needs to sync with events that have happened
67: 	unsynced watcherGroup
68: 
69: 	// contains all synced watchers that are in sync with the progress of the store.
70: 	// The key of the map is the key that the watcher watches on.
71: 	synced watcherGroup
72: 
73: 	stopc chan struct{}
74: 	wg    sync.WaitGroup
75: }
76: 
77: var _ WatchableKV = (*watchableStore)(nil)
78: 
79: // cancelFunc updates unsynced and synced maps when running
80: // cancel operations.
81: type cancelFunc func()
82: 
83: func New(lg *zap.Logger, b backend.Backend, le lease.Lessor, cfg StoreConfig) WatchableKV {
84: 	s := newWatchableStore(lg, b, le, cfg)
85: 	s.wg.Add(2)
86: 	go s.syncWatchersLoop()
87: 	go s.syncVictimsLoop()
88: 	return s
89: }
