284: // moveVictims tries to update watches with already pending event data
285: func (s *watchableStore) moveVictims() (moved int) {
286: 	s.mu.Lock()
287: 	victims := s.victims
288: 	s.victims = nil
289: 	s.mu.Unlock()
290: 
291: 	var newVictim watcherBatch
292: 	for _, wb := range victims {
293: 		// try to send responses again
294: 		for w, eb := range wb {
295: 			// watcher has observed the store up to, but not including, w.minRev
296: 			rev := w.minRev - 1
297: 			if !w.send(WatchResponse{WatchID: w.id, Events: eb.evs, Revision: rev}) {
298: 				if newVictim == nil {
299: 					newVictim = make(watcherBatch)
300: 				}
301: 				newVictim[w] = eb
302: 				continue
303: 			}
304: 			pendingEventsGauge.Add(float64(len(eb.evs)))
305: 			moved++
306: 		}
307: 
308: 		// assign completed victim watchers to unsync/sync
309: 		s.mu.Lock()
310: 		s.store.revMu.RLock()
311: 		curRev := s.store.currentRev
312: 		for w, eb := range wb {
313: 			if newVictim != nil && newVictim[w] != nil {
314: 				// couldn't send watch response; stays victim
315: 				continue
316: 			}
317: 			w.victim = false
318: 			if eb.moreRev != 0 {
319: 				w.minRev = eb.moreRev
320: 			}
321: 			if w.minRev <= curRev {
322: 				s.unsynced.add(w)
323: 			} else {
324: 				slowWatcherGauge.Dec()
325: 				s.synced.add(w)
326: 			}
327: 		}
328: 		s.store.revMu.RUnlock()
329: 		s.mu.Unlock()
330: 	}
331: 
332: 	if len(newVictim) > 0 {
333: 		s.mu.Lock()
334: 		s.victims = append(s.victims, newVictim)
335: 		s.mu.Unlock()
336: 	}
337: 
338: 	return moved
339: }
