22: const (
23: 	// revBytesLen is the byte length of a normal revision.
24: 	// First 8 bytes is the revision.main in big-endian format. The 9th byte
25: 	// is a '_'. The last 8 bytes is the revision.sub in big-endian format.
26: 	revBytesLen = 8 + 1 + 8
27: 	// markedRevBytesLen is the byte length of marked revision.
28: 	// The first `revBytesLen` bytes represents a normal revision. The last
29: 	// one byte is the mark.
30: 	markedRevBytesLen      = revBytesLen + 1
31: 	markBytePosition       = markedRevBytesLen - 1
32: 	markTombstone     byte = 't'
33: )
34: 
35: type Revision struct {
36: 	// Main is the main revision of a set of changes that happen atomically.
37: 	Main int64
38: 	// Sub is the sub revision of a change in a set of changes that happen
39: 	// atomically. Each change has different increasing sub revision in that
40: 	// set.
41: 	Sub int64
42: }
43: 
44: func (a Revision) GreaterThan(b Revision) bool {
45: 	if a.Main > b.Main {
46: 		return true
47: 	}
48: 	if a.Main < b.Main {
49: 		return false
50: 	}
51: 	return a.Sub > b.Sub
52: }
