62: // BucketKey indicates modification of the key-value space.
63: // The set of changes that share same main revision changes the key-value space atomically.
64: type BucketKey struct {
65: 	Revision
66: 	tombstone bool
67: }
68: 
69: func newBucketKey(main, sub int64, isTombstone bool) BucketKey {
70: 	return BucketKey{
71: 		Revision: Revision{
72: 			Main: main,
73: 			Sub:  sub,
74: 		},
75: 		tombstone: isTombstone,
76: 	}
77: }
