79: func NewRevBytes() []byte {
80: 	return make([]byte, revBytesLen, markedRevBytesLen)
81: }
82: 
83: func BucketKeyToBytes(rev BucketKey, bytes []byte) []byte {
84: 	binary.BigEndian.PutUint64(bytes, uint64(rev.Main))
85: 	bytes[8] = '_'
86: 	binary.BigEndian.PutUint64(bytes[9:], uint64(rev.Sub))
87: 	if rev.tombstone {
88: 		switch len(bytes) {
89: 		case revBytesLen:
90: 			bytes = append(bytes, markTombstone)
91: 		case markedRevBytesLen:
92: 			bytes[markBytePosition] = markTombstone
93: 		}
94: 	}
95: 	return bytes
96: }
97: 
98: func BytesToBucketKey(bytes []byte) BucketKey {
99: 	if (len(bytes) != revBytesLen) && (len(bytes) != markedRevBytesLen) {
100: 		panic(fmt.Sprintf("invalid revision length: %d", len(bytes)))
101: 	}
102: 	if bytes[8] != '_' {
103: 		panic(fmt.Sprintf("invalid separator in bucket key: %q", bytes[8]))
104: 	}
105: 	main := int64(binary.BigEndian.Uint64(bytes[0:8]))
106: 	sub := int64(binary.BigEndian.Uint64(bytes[9:]))
107: 	if main < 0 || sub < 0 {
108: 		panic(fmt.Sprintf("negative revision: main=%d sub=%d", main, sub))
109: 	}
110: 	return BucketKey{
111: 		Revision: Revision{
112: 			Main: main,
113: 			Sub:  sub,
114: 		},
115: 		tombstone: isTombstone(bytes),
116: 	}
117: }
