119: // isTombstone checks whether the revision bytes is a tombstone.
120: func isTombstone(b []byte) bool {
121: 	return len(b) == markedRevBytesLen && b[markBytePosition] == markTombstone
122: }
123: 
124: func IsTombstone(b []byte) bool {
125: 	return isTombstone(b)
126: }
